from . import utl_interface
import logging
import unreal
import dataclasses
import pathlib
from typing import List

@dataclasses.dataclass
class ImportInterfaceParams:
    file_path: str = ""
    dst_name: str = ""
    destination_path: str = ""
    replace_existing: bool = True

    def __post_init__(self):
        if not self.destination_path:
            raise ValueError("目标路径不能为空")
        if not self.dst_name:
            self.dst_name = pathlib.Path(self.file_path).stem


@dataclasses.dataclass
class CFXImportParams(ImportInterfaceParams):
    frame_start: int = 0
    frame_end: int = 0
    create_materials: bool = True
    ...

class ImportInterface(utl_interface.UnrealInterface):

    def __init__(self, logger: logging.Logger = None):
        super().__init__(logger)
        self.import_params = None

    @utl_interface.add_logger
    def exec(self, import_params: ImportInterfaceParams):
        self.import_params = import_params
        res = []
        try:
            res = self.import_impl()
        except Exception as e:
            self.logger.error(f"导入失败: {str(e)}")
        self.import_params = None
        return res
    
    def import_impl(self) -> List[unreal.Object]:
        raise NotImplementedError("Subclasses must implement this method.")
    

class ImportCFXInterface(ImportInterface):

    def __init__(self, logger: logging.Logger = None):
        super().__init__(logger)
    
    def import_impl(self) -> List[unreal.GeometryCache]:
        """
        执行导入操作
        """
        res = []
        asset_tool = unreal.AssetToolsHelpers.get_asset_tools()
        task = self.get_cfx_import_task()
        asset_tool.import_asset_tasks([task])
        for i in task.get_editor_property("imported_object_paths"):
            if utl_interface.editor_asset_system.does_asset_exist(i):
                res.append(unreal.load_asset(i))
        return res

    def get_cfx_import_task(self):
        import_task = unreal.AssetImportTask()
        import_task.filename = self.import_params.file_path
        import_task.destination_path = self.import_params.destination_path
        import_task.replace_existing = True
        import_task.automated = True
        import_task.save = True
        import_task.destination_name = self.import_params.dst_name
        options = None
        options = unreal.AbcImportSettings()
        options.material_settings.create_materials = self.import_params.create_materials
        options.import_type = unreal.AlembicImportType.GEOMETRY_CACHE
        options.sampling_settings.sampling_type = unreal.AlembicSamplingType.PER_FRAME
        options.sampling_settings.frame_start = int(self.import_params.frame_start)
        options.sampling_settings.frame_end = int(self.import_params.frame_end)
        options.conversion_settings = unreal.AbcConversionSettings(
            preset=unreal.AbcConversionPreset.CUSTOM, rotation=(90, 0, 0)
        )
        import_task.options = options
        return import_task
    
class ImportRigInterface(ImportInterface):

    def __init__(self, logger: logging.Logger = None):
        super().__init__(logger)
    
    def import_impl(self) -> List[unreal.SkeletalMesh]:
        print("import_impl")
        if utl_interface.UnrealUTLInterface(self.logger).useful_interchanged():
            self.import_by_interchanged()
        else:
            self.import_by_task()
    
    def import_by_interchanged(self) -> List[unreal.SkeletalMesh]:
        
        out_res = []

        source_data = unreal.InterchangeManager.create_source_data(self.import_params.file_path)
        pipeline = unreal.InterchangeGenericAssetsPipeline()
        import_asset_parameters = unreal.ImportAssetParameters()
        import_asset_parameters.is_automated = True
        import_asset_parameters.replace_existing = True
        import_asset_parameters.override_pipelines.append(unreal.SoftObjectPath(pipeline.get_path_name()))
        if self.import_params.dst_name:
            import_asset_parameters.destination_name = self.import_params.dst_name
        mesh_property = unreal.InterchangeGenericCommonMeshesProperties()
        mesh_property.import_lods = True
        mesh_property.force_all_mesh_as_type = unreal.InterchangeForceMeshType.IFMT_SKELETAL_MESH
        mesh_property.vertex_color_import_option = unreal.InterchangeVertexColorImportOption.IVCIO_REPLACE
        self.__set_mesh_pipeline(pipeline.mesh_pipeline)
        interchange_manager = unreal.InterchangeManager.get_interchange_manager_scripted()
        import_result = interchange_manager.import_asset(self.import_params.destination_path, source_data, import_asset_parameters)
        if import_result: out_res.extend(import_result)
        self.temp_skeleton = None
        return out_res
    
    def __set_mesh_pipeline(self, mesh_pipeline):
        mesh_pipeline.import_skeletal_meshes = True
        mesh_pipeline.skeletal_mesh_import_content_type = unreal.InterchangeSkeletalMeshContentType.ALL
        mesh_pipeline.import_morph_targets = True

    def import_by_task(self) -> List[unreal.SkeletalMesh]:
        task_list = []
        task = self.__create_task(self.import_params)
        task_list.append(task)
        if task_list:
            asset_tool = unreal.AssetToolsHelpers.get_asset_tools()
            asset_tool.import_asset_tasks(task_list)

    def __create_task(self, in_param: ImportInterfaceParams):
        import_task = unreal.AssetImportTask()
        options = unreal.FbxImportUI()
        import_task.replace_existing = True
        import_task.options = options
        import_task.save = True
        import_task.automated = True
        import_task.filename = in_param.file_path
        import_task.destination_path = in_param.destination_path
        options.import_as_skeletal = True
        options.import_materials = False
        options.import_mesh = True
        options.import_textures = False
        import_data = unreal.FbxSkeletalMeshImportData()
        import_data.set_editor_property("import_content_type", unreal.FBXImportContentType.FBXICT_ALL)
        options.set_editor_property("skeletal_mesh_import_data", import_data)
        return import_task